import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { LinkedinIcon, ExternalLink, Quote, CheckCircle } from "lucide-react";
import { motion } from "framer-motion";
import profilePhoto from "@assets/profile-photo_1758789332956.jpg";

export default function About() {
  const achievements = [
    "500,000+ Individuals Trained Globally",
    "5000+ Workshops & Seminars Conducted", 
    "1000+ Corporate Clients Served",
    "1200+ Education Institutions Partnered"
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
        duration: 0.6
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" }
    }
  };

  return (
    <section id="about" className="py-16 lg:py-32 px-4 sm:px-6 lg:px-8 relative overflow-hidden">
      {/* Background Graphics */}
      <div className="absolute inset-0 bg-gradient-to-br from-muted/30 via-background to-primary/5" />
      <div className="absolute top-20 left-10 w-32 h-32 bg-chart-2/10 rounded-full blur-3xl" />
      <div className="absolute bottom-20 right-10 w-40 h-40 bg-chart-1/10 rounded-full blur-3xl" />

      <motion.div 
        className="max-w-7xl mx-auto relative z-10"
        variants={containerVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: "-100px" }}
      >
        <motion.div className="text-center mb-16 lg:mb-24" variants={itemVariants}>
          <h2 className="text-3xl sm:text-4xl lg:text-6xl font-bold mb-6">
            Meet the <span className="gradient-text">Founder</span>
          </h2>
          <p className="text-lg sm:text-xl lg:text-2xl text-muted-foreground max-w-3xl mx-auto leading-relaxed">
            A globally recognized behavioural trainer, transformational mentor, and pioneering face reading expert with over four decades of experience
          </p>
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-20 items-center mb-20">
          {/* Profile Photo */}
          <motion.div 
            className="flex justify-center lg:justify-start order-2 lg:order-1"
            variants={itemVariants}
          >
            <motion.div 
              className="relative group"
              whileHover={{ scale: 1.05 }}
              transition={{ duration: 0.3 }}
            >
              <div className="absolute inset-0 bg-gradient-to-r from-primary/20 to-chart-1/20 rounded-3xl blur-2xl group-hover:blur-3xl transition-all duration-300" />
              <div className="relative">
                <img
                  src={profilePhoto}
                  alt="Zane E. Cuxton - Founder of Academy for Skill and Knowledge"
                  className="w-80 h-80 lg:w-96 lg:h-96 rounded-3xl object-cover shadow-2xl relative z-10"
                  data-testid="img-founder-photo"
                />
                <div className="absolute inset-0 rounded-3xl bg-gradient-to-t from-primary/30 via-transparent to-transparent" />
              </div>
            </motion.div>
          </motion.div>

          {/* About Content */}
          <motion.div className="space-y-8 order-1 lg:order-2" variants={itemVariants}>
            <div>
              <motion.h3 
                className="text-3xl lg:text-4xl font-bold text-foreground mb-3"
                whileInView={{ scale: [0.8, 1] }}
                transition={{ duration: 0.5 }}
              >
                Zane E. Cuxton
              </motion.h3>
              <p className="text-lg lg:text-xl text-primary font-semibold mb-6">
                Behavioural Trainer | Body Language & Face Reading Expert | Founder – ASK & FRFW
              </p>

              <div className="space-y-4 text-foreground text-base lg:text-lg leading-relaxed">
                <motion.p
                  initial={{ opacity: 0, x: -20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.2 }}
                >
                  Originally trained in the pharmaceutical industry, Zane began his professional journey 
                  in sales and marketing, serving as Vice President – Marketing for 12 years. An ISO-certified 
                  trainer and postgraduate in Sales, he founded the Academy for Skill and Knowledge (ASK) in 
                  1995 as "The Anvil to Shape Careers."
                </motion.p>

                <motion.p
                  initial={{ opacity: 0, x: -20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.4 }}
                >
                  In 2000, Zane established the Face Readers Foundation of the World (FRFW), pioneering the 
                  integration of face reading, body language analysis, and micro-expression techniques into 
                  professional development. He specializes in behavioural skills, emotional intelligence, 
                  leadership development, and human dynamics.
                </motion.p>

                <motion.p
                  initial={{ opacity: 0, x: -20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.6 }}
                >
                  His work has been featured on BBC, Discovery, STAR Network, Times of India, and numerous 
                  other media outlets. Zane has worked with elite institutions including IITs, IIMs, NACEN, 
                  and the Tamil Nadu Police Department, transforming lives through his intuitive insights 
                  and practical training programs.
                </motion.p>
              </div>
            </div>

            {/* Achievements */}
            <div className="space-y-3">
              {achievements.map((achievement, index) => (
                <motion.div
                  key={index}
                  className="flex items-center space-x-3"
                  initial={{ opacity: 0, x: -20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1 * index }}
                >
                  <CheckCircle className="w-5 h-5 text-chart-2 flex-shrink-0" />
                  <span className="text-foreground font-medium">{achievement}</span>
                </motion.div>
              ))}
            </div>

            <motion.div 
              className="flex flex-col sm:flex-row gap-4 pt-4"
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.8 }}
            >
              <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                <Button 
                  variant="outline" 
                  className="glass hover:bg-primary/10 transition-all duration-300"
                  onClick={() => window.open('https://www.linkedin.com/in/zane-cuxton-b105bb7', '_blank')}
                  data-testid="button-linkedin-profile"
                >
                  <LinkedinIcon className="w-4 h-4" />
                  <span className="mx-2">LinkedIn Profile</span>
                  <ExternalLink className="w-4 h-4" />
                </Button>
              </motion.div>

              <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                <Button 
                  className="bg-gradient-to-r from-chart-1 to-chart-1/80 hover:from-chart-1/90 hover:to-chart-1/70 shadow-orange-glow"
                  onClick={() => {
                    const element = document.querySelector("#contact");
                    if (element) element.scrollIntoView({ behavior: "smooth" });
                  }}
                  data-testid="button-schedule-consultation"
                >
                  Schedule Consultation
                </Button>
              </motion.div>
            </motion.div>
          </motion.div>
        </div>

        {/* Vision Statement */}
        <motion.div 
          className="text-center"
          variants={itemVariants}
        >
          <Card className="p-8 lg:p-12 max-w-5xl mx-auto glass border-primary/20 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-chart-1 to-chart-2" />

            <Quote className="w-8 h-8 lg:w-12 lg:h-12 text-primary mx-auto mb-6 opacity-50" />

            <h4 className="text-2xl lg:text-3xl font-bold text-foreground mb-6">Our Vision</h4>
            <p className="text-lg lg:text-xl text-muted-foreground italic leading-relaxed max-w-3xl mx-auto">
              "To unlock human potential by integrating the science of face reading, body language, 
              and emotional intelligence with modern leadership development—empowering individuals and 
              organizations to decode human behaviour, build authentic connections, and achieve 
              transformational success."
            </p>

            <div className="mt-8">
              <div className="w-16 h-1 bg-gradient-to-r from-primary to-chart-1 mx-auto rounded-full" />
            </div>
          </Card>
        </motion.div>
      </motion.div>
    </section>
  );
}

client/src/components/Contact.tsx.content:
import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Phone, Mail, MapPin, Send, MessageCircle, Sparkles } from "lucide-react";
import { motion } from "framer-motion";
import { useToast } from "@/hooks/use-toast";

export default function Contact() {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    message: ""
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const response = await fetch('/api/contact', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to send message');
      }

      const data = await response.json();

      toast({
        title: "Message Sent!",
        description: data.message || "Thank you for your inquiry. We'll get back to you within 24 hours.",
      });

      setFormData({ name: "", email: "", phone: "", message: "" });
    } catch (error) {
      console.error('Error sending message:', error);
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to send message. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const contactInfo = [
    {
      icon: Phone,
      label: "Phone",
      value: "+91 9844324100",
      href: "tel:+919844324100",
      color: "text-chart-1",
      gradient: "from-chart-1/10 to-chart-1/5"
    },
    {
      icon: Mail,
      label: "Email", 
      value: "asktrainersblore@gmail.com",
      href: "mailto:asktrainersblore@gmail.com",
      color: "text-primary",
      gradient: "from-primary/10 to-primary/5"
    },
    {
      icon: MapPin,
      label: "Location",
      value: "Lingarajapuram, Bangalore – 560 084",
      href: null,
      color: "text-chart-2",
      gradient: "from-chart-2/10 to-chart-2/5"
    }
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
        duration: 0.6
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" }
    }
  };

  return (
    <section id="contact" className="py-16 lg:py-32 px-4 sm:px-6 lg:px-8 relative overflow-hidden">
      {/* Background Graphics */}
      <div className="absolute inset-0 bg-gradient-to-br from-primary/5 via-background to-chart-1/5" />
      <div className="absolute -top-40 -left-40 w-80 h-80 bg-chart-2/5 rounded-full blur-3xl animate-float" />
      <div className="absolute -bottom-40 -right-40 w-96 h-96 bg-primary/5 rounded-full blur-3xl animate-float" style={{ animationDelay: "2s" }} />

      <motion.div 
        className="max-w-7xl mx-auto relative z-10"
        variants={containerVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: "-100px" }}
      >
        <motion.div className="text-center mb-16 lg:mb-24" variants={itemVariants}>
          <h2 className="text-3xl sm:text-4xl lg:text-6xl font-bold mb-6">
            Get In <span className="gradient-text">Touch</span>
          </h2>
          <p className="text-lg sm:text-xl lg:text-2xl text-muted-foreground max-w-3xl mx-auto leading-relaxed">
            Ready to start your journey? Contact us today for a free consultation and discover how we can help you achieve your goals.
          </p>
        </motion.div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-16">
          {/* Contact Information */}
          <motion.div className="space-y-8" variants={itemVariants}>
            <Card className="glass border-2 hover:border-primary/20 shadow-lg hover:shadow-2xl transition-all duration-500 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-chart-1 to-chart-2" />
              <CardHeader className="pb-4">
                <CardTitle className="text-xl lg:text-2xl flex items-center space-x-2">
                  <MessageCircle className="w-5 h-5 text-primary" />
                  <span>Contact Information</span>
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-6">
                {contactInfo.map((info, index) => {
                  const IconComponent = info.icon;
                  return (
                    <motion.div
                      key={index}
                      className="flex items-center space-x-4 p-3 rounded-lg glass hover-elevate transition-all duration-300"
                      whileHover={{ x: 5 }}
                      initial={{ opacity: 0, x: -20 }}
                      whileInView={{ opacity: 1, x: 0 }}
                      transition={{ delay: index * 0.1 }}
                    >
                      <div className={`p-4 bg-gradient-to-br ${info.gradient} rounded-xl relative overflow-hidden`}>
                        <IconComponent className={`w-5 h-5 ${info.color} relative z-10`} />
                        <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent" />
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground font-medium">{info.label}</p>
                        {info.href ? (
                          <a 
                            href={info.href}
                            className="text-foreground hover:text-primary transition-colors font-semibold text-base lg:text-lg"
                            data-testid={`link-${info.label.toLowerCase()}`}
                          >
                            {info.value}
                          </a>
                        ) : (
                          <p className="text-foreground font-semibold text-base lg:text-lg" data-testid={`text-${info.label.toLowerCase()}`}>
                            {info.value}
                          </p>
                        )}
                      </div>
                    </motion.div>
                  );
                })}
              </CardContent>
            </Card>

            <motion.div
              whileHover={{ scale: 1.02 }}
              transition={{ duration: 0.3 }}
            >
              <Card className="glass border-2 border-chart-1/20 shadow-orange-glow relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-chart-1 to-chart-1/70" />
                <div className="absolute -top-10 -right-10 w-20 h-20 bg-chart-1/10 rounded-full blur-xl" />

                <CardContent className="text-center p-8 relative z-10">
                  <motion.div
                    whileHover={{ scale: 1.1, rotate: 5 }}
                    className="inline-flex p-4 bg-gradient-to-br from-chart-1/20 to-chart-1/5 rounded-full mb-6"
                  >
                    <Sparkles className="w-6 h-6 text-chart-1" />
                  </motion.div>

                  <h3 className="text-xl lg:text-2xl font-bold text-foreground mb-4">
                    Free Consultation Available
                  </h3>
                  <p className="text-muted-foreground text-base lg:text-lg mb-6 leading-relaxed">
                    Book a free 30-minute consultation to discuss your career goals and how we can help you achieve them.
                  </p>

                  <motion.div
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                  >
                    <Button 
                      className="bg-gradient-to-r from-chart-1 to-chart-1/80 hover:from-chart-1/90 hover:to-chart-1/70 shadow-orange-glow w-full text-lg"
                      data-testid="button-book-free-consultation"
                    >
                      <Phone className="w-4 h-4 mr-2" />
                      Book My Free Call
                    </Button>
                  </motion.div>
                </CardContent>
              </Card>
            </motion.div>
          </motion.div>

          {/* Contact Form */}
          <motion.div variants={itemVariants}>
            <Card className="glass border-2 hover:border-primary/20 shadow-lg hover:shadow-2xl transition-all duration-500 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-chart-2 to-chart-1" />
              <CardHeader className="pb-6">
                <CardTitle className="text-xl lg:text-2xl flex items-center space-x-2">
                  <Send className="w-5 h-5 text-primary" />
                  <span>Send us a Message</span>
                </CardTitle>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleSubmit} className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <motion.div 
                      className="space-y-2"
                      whileFocus={{ scale: 1.02 }}
                    >
                      <Label htmlFor="name" className="text-sm font-semibold">Name *</Label>
                      <Input
                        id="name"
                        name="name"
                        value={formData.name}
                        onChange={handleInputChange}
                        required
                        placeholder="Your full name"
                        className="glass border-2 focus:border-primary/50 transition-all duration-300"
                        data-testid="input-contact-name"
                      />
                    </motion.div>
                    <motion.div 
                      className="space-y-2"
                      whileFocus={{ scale: 1.02 }}
                    >
                      <Label htmlFor="phone" className="text-sm font-semibold">Phone</Label>
                      <Input
                        id="phone"
                        name="phone"
                        type="tel"
                        value={formData.phone}
                        onChange={handleInputChange}
                        placeholder="Your phone number"
                        className="glass border-2 focus:border-primary/50 transition-all duration-300"
                        data-testid="input-phone"
                      />
                    </motion.div>
                  </div>

                  <motion.div 
                    className="space-y-2"
                    whileFocus={{ scale: 1.02 }}
                  >
                    <Label htmlFor="email" className="text-sm font-semibold">Email *</Label>
                    <Input
                      id="email"
