  const handleEditBlog = (blog: Blog) => {
    setSelectedBlog(blog);
    reset({
      title: blog.title,
      content: blog.content,
      summary: blog.summary || "",
      slug: blog.slug,
      author: blog.author,
      status: blog.status as 'draft' | 'published' | 'archived',
